mapper.sql:
d.money is not null
and c.store_id=#{store_id}
and a.id=#{id}
and a.is_mch=#{isMch}
and a.main_id=#{main_id}
and c.user_id=#{userid}
AND c.zhanghao like concat('%',#{zhangHao},'%')
and money_type=#{type}
AND a.type=#{otype}
AND c.user_name like concat('%',#{like_name},'%')
AND (c.user_id like concat('%',#{key},'%') or c.user_name like concat('%',#{key},'%') or
    c.mobile like concat('%',#{key},'%'))

AND l.status = #{ostatus}
AND c.mobile like concat('%',#{like_mobile},'%')
AND a.add_date  >=  #{startDate}
AND a.add_date  <=  #{endDate}

    
        #{type}
    


    
        #{typeName}

mapper.select:
select a.id,a.user_id, c.user_name, c.mobile, c.source,c.zhanghao, c.Register_data,a.event,a.add_date,a.type as recordType,d.money_type_name, d.money,d.type, a.details_id,d.money_type as moneyType,d.record_notes as remake, CASE c.source WHEN 1 THEN '小程序' WHEN 2 THEN 'H5移动端' WHEN 3 THEN '支付宝小程序' WHEN 4 THEN '头条小程序' WHEN 5 THEN '百度小程序' WHEN 6 THEN 'PC端' WHEN 11 THEN 'APP端' ELSE '未知' END as sourceName, CASE d.type WHEN 1 THEN '用户充值' WHEN 2 THEN '平台充值' WHEN 4 THEN '退款入账' WHEN 5 THEN '店铺保证金提取' WHEN 10 THEN '店铺保证金支付' WHEN 7 THEN '订单付款' WHEN 11 THEN '余额提现' WHEN 12 THEN '保证金退回' WHEN 9 THEN '会员开通' WHEN 13 THEN '会员续费' WHEN 14 THEN '系统充值' when 42 then '直播佣金转入' when 8 then case d.money_type_name when 8 then '预售活动定金' when 18 then '竞拍保证金缴纳' end ELSE '未知' END as typeName from lkt_record as a left join lkt_user as c on c.user_id = a.user_id left join lkt_record_details d on a.details_id = d.id
order by a.add_date desc
LIMIT #{pageStart},#{pageEnd}
